class Complex {
private:
 int real;
 int imag;

public:
 // Default constructor
 Complex() {
 real = 0;
 imag = 0;
 }

 // Parameterized constructor
 Complex(int r, int i) {
 real = r;
 imag = i;
 }

 // Copy constructor
 Complex(const Complex& obj) {
 real = obj.real;
 imag = obj.imag;
 }

 void display() {
 cout << real << " + " << imag << "i" << endl;
 }
};

int main() {
 Complex c1; // Calls default
 Complex c2(5, 3); // Calls parameterized
 Complex c3(c2); // Calls copy constructor
 c1.display();
 c2.display();
 c3.display();
 return 0;
}

class String {
private:
 char* str;
 int length;

public:
 // Parameterized constructor
 String(const char* s) {
 length = strlen(s);
 str = new char[length + 1];
 strcpy(str, s);
 }

 // Deep copy constructor
 String(const String& obj) {
 length = obj.length;
 str = new char[length + 1]; // Allocate new memory
 strcpy(str, obj.str); // Copy actual data
 }

 // Destructor
 ~String() {
 delete[] str;
 }
};

int main() {
 String s1("Hello");
 String s2(s1); // Deep copy - s2 has independent memory
 return 0;
}

class Rectangle {
private:
 int width, height;

public:
 // Primary constructor
 Rectangle(int w, int h) : width(w), height(h) {
 cout << "Primary constructor" << endl;
 }

 // Delegating constructor - delegates to primary
 Rectangle(int size) : Rectangle(size, size) {
 cout << "Delegating constructor" << endl;
 }

 // Default constructor - delegates to primary
 Rectangle() : Rectangle(1, 1) {
 cout << "Default constructor" << endl;
 }

 void display() {
 cout << "Width: " << width << ", Height: " << height << endl;
 }
};

int main() {
 Rectangle r1; // Calls default, which delegates
 Rectangle r2(5); // Calls single-param constructor
 Rectangle r3(3, 4); // Calls primary constructor
 return 0;
}

class Student {
private:
 const int id; // Must be initialized in list
 int& marks; // Must be initialized in list
 string name;

public:
 // Initialization list is MUST for id and marks
 Student(int studentId, int& studentMarks, string n) 
 : id(studentId), marks(studentMarks), name(n) {
 // Constructor body can also initialize other members
 }

 void display() {
 cout << "ID: " << id << ", Name: " << name 
 << ", Marks: " << marks << endl;
 }
};

int main() {
 int m = 95;
 Student s(101, m, "John");
 s.display();
 return 0;
}

class Singleton {
private:
 static Singleton* instance;
 int data;

 // Private constructor
 Singleton() {
 data = 0;
 }

public:
 // Static method to get instance
 static Singleton* getInstance() {
 if (instance == NULL) {
 instance = new Singleton();
 }
 return instance;
 }

 void setData(int d) { data = d; }
 int getData() { return data; }
};

// Initialize static member
Singleton* Singleton::instance = NULL;

int main() {
 Singleton* s1 = Singleton::getInstance();
 s1->setData(100);
 Singleton* s2 = Singleton::getInstance();
 // s1 and s2 point to same instance
 cout << s2->getData() << endl; // Prints 100
 return 0;
}
